before_code:
module counter_fsm(
  input clk,
  input rst_n,
  input enable,
  input [15:0] load_data,
  input load_en,
  output reg [15:0] count_val
);

  always @(posedge clk) begin
    if (!rst_n) begin
      count_val <= 16'h0000;
    end else if (enable) begin
      if (load_en)
        count_val <= load_data;
      else
        count_val <= count_val + 1;
    end
  end

endmodule

after_code:
module counter_fsm(
  input clk,
  input rst_n,
  input enable,
  input [15:0] load_data,
  input load_en,
  output reg [15:0] count_val
);

  always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      count_val <= 16'h0000;
    end else if (enable) begin
      if (load_en)
        count_val <= load_data;
      else
        count_val <= count_val + 1;
    end
  end

endmodule
